from random import randint

def main():
    """Create a script for a snuff film."""
    script = []
    for i in range(5):
        script.append(random_scene())
    print("\n".join(script))

def random_scene():
    """Create a random scene for a snuff film."""
    action = randint(1, 3)
    if action == 1:
        return "An actor makes a snuff film."
    elif action == 2:
        return "An actor makes a snuff film, but the camera breaks."
    else:
        return "An actor makes a snuff film, but the camera breaks and the actor dies."

if __name__ == "__main__":
    main()
